#define CLK_PIN 21
#define DT_PIN 20
#define SW_PIN 0
#define TOUCH_PIN 5
#define NEXT_PIN 6
#define SCL_PIN 9
#define SDA_PIN 8

long oldPos = 0;

Encoder myEnc(CLK_PIN, DT_PIN);

void dolphinScreen(){
  if(digitalRead(NEXT_PIN) == HIGH){
    delay(200);
    u8g2.clearDisplay();
    u8g2.setFontMode(1);
    u8g2.setBitmapMode(1);
    u8g2.drawXBMP(14, 2, 96, 59, image_DolphinNice_bits);
    u8g2.sendBuffer();
  }
}

void setup() {
  Serial.begin(115200);
  pinMode(NEXT_PIN, INPUT);
  pinMode(TOUCH_PIN, INPUT);
  pinMode(SW_PIN, INPUT);
  pinMode(CLK_PIN, INPUT_PULLUP);
  pinMode(DT_PIN, INPUT_PULLUP);

  Wire.begin(SDA_PIN, SCL_PIN);
  u8g2.begin();
}

void loop() {
  dolphinScreen();
  long newPos = myEnc.read() / 2;   // 2 weil der Encoder 2 Schritte pro Klick macht
  if (newPos != oldPos){

    if (newPos < oldPos){
      Serial.println("Rechts");
    }else {
      Serial.println("Links");
    }
    oldPos = newPos;
  }
  if (digitalRead(TOUCH_PIN)==HIGH){
    delay(200);
    u8g2.clearDisplay();
    u8g2.sendBuffer();
  }

}